//! # Hello Holograph — End-to-End Visual Handshake
//!
//! Generates a "Hello World" execution path, encodes it as a
//! Topological QR, and exports a rotation sequence for video assembly.

use distributed_inference::pleromatic_frame::{MonsterPath, SignalToken};
use distributed_inference::topological_qr::TopologicalQR;
use std::process::Command;

fn main() -> Result<(), Box<dyn std::error::Error>> {
    println!(" [ GENERATING TOPOLOGICAL HANDSHAKE ] ");

    // 1. Define the "Hello World" Execution Path (The Green Path)
    let path: MonsterPath = vec![
        SignalToken::T,
        SignalToken::S,
        SignalToken::T,
        SignalToken::F { r: 0 },
        SignalToken::S,
        SignalToken::L,
        SignalToken::V,
    ];

    // 2. Encode into Topological QR (Spatial Fingerprint)
    let qr = TopologicalQR::encode(&path);

    // 3. Save Static Artifacts
    println!(" Saving static artifacts...");
    qr.save_as_png("hello_fingerprint.png")?;
    qr.save_as_webp("hello_fingerprint.webp")?;
    qr.save_as_ppm("hello_fingerprint.ppm")?;
    println!("  - hello_fingerprint.png");
    println!("  - hello_fingerprint.webp");

    // 4. Export Rotation Sequence (60 frames)
    println!(" Exporting rotation sequence (60 frames)...");
    let frame_dir = "handshake_frames";
    qr.export_rotation_sequence(frame_dir, 60)?;
    println!("  - Saved to {}/", frame_dir);

    // 5. Assemble Video via ffmpeg
    println!(" Assembling video via ffmpeg...");
    let ffmpeg_out = Command::new("ffmpeg")
        .args([
            "-y", // Overwrite output
            "-framerate",
            "30", // 30 fps
            "-i",
            "handshake_frames/frame_%04d.png",
            "-c:v",
            "libvpx-vp9", // WebM format
            "-pix_fmt",
            "yuva420p", // Support transparency
            "handshake.webm",
        ])
        .output()?;

    if ffmpeg_out.status.success() {
        println!(" [ SUCCESS ] handshake.webm generated.");
    } else {
        eprintln!(
            " [ ERROR ] ffmpeg failed: {}",
            String::from_utf8_lossy(&ffmpeg_out.stderr)
        );
    }

    Ok(())
}
